Here's the refactored code using async/await with proper error handling:

```js
async function run() {
  let user, orders, enriched;

  try {
    user = await promisify(fetchUser)(id);
  } catch (err) {
    console.error('Failed at: fetchUser');
    throw err;
  }

  try {
    orders = await promisify(fetchOrders)(user.id);
  } catch (err) {
    console.error('Failed at: fetchOrders');
    throw err;
  }

  try {
    enriched = await promisify(enrichOrders)(orders);
  } catch (err) {
    console.error('Failed at: enrichOrders');
    throw err;
  }

  return { user, orders: enriched };
}

// Helper function to convert callback-based functions to promises
function promisify(fn) {
  return (...args) => {
    return new Promise((resolve, reject) => {
      fn(...args, (err, result) => {
        if (err) reject(err);
        else resolve(result);
      });
    });
  };
}
```

Alternatively, if you prefer a cleaner approach with less repetition:

```js
async function run() {
  const steps = [
    { name: 'fetchUser', fn: () => promisify(fetchUser)(id) },
    { name: 'fetchOrders', fn: (user) => promisify(fetchOrders)(user.id) },
    { name: 'enrichOrders', fn: (user, orders) => promisify(enrichOrders)(orders) }
  ];

  const results = [];

  for (const step of steps) {
    try {
      const result = await step.fn(...results);
      results.push(result);
    } catch (err) {
      console.error(`Failed at: ${step.name}`);
      throw err;
    }
  }

  const [user, orders, enriched] = results;
  return { user, orders: enriched };
}

function promisify(fn) {
  return (...args) => {
    return new Promise((resolve, reject) => {
      fn(...args, (err, result) => {
        if (err) reject(err);
        else resolve(result);
      });
    });
  };
}
```

Both versions:
- Convert callback-based functions to promises using the `promisify` helper
- Log the specific step name when an error occurs
- Rethrow the error to maintain the same error propagation behavior
- Return the same result structure as the original
